// Collapse every filtered station into ONE item holding comma-joined
// coordinate lists — this is what lets the next node fetch wind data
// for all stations in a single Open-Meteo call instead of one per station.
const stations = items.map(i => i.json);
return [{
  json: {
    latitudes: stations.map(s => s.lat).join(','),
    longitudes: stations.map(s => s.lon).join(',')
  }
}];

// Get ALL weather data from ALL items (Open-Meteo returns each as a separate item)
const weatherItems = $input.all();
const weatherArray = weatherItems.map(item => item.json);

console.log('Weather items count:', weatherArray.length);

// Get stations with AQICN details (from Normalize AQICN Detail node)
const stations = $('Normalize AQICN Detail').all().map(item => item.json);
console.log('Stations count:', stations.length);

// Match each station to the closest weather data point
const merged = stations.map(station => {
  let bestMatch = null;
  let bestDistance = Infinity;

  // Find closest weather point
  for (const weather of weatherArray) {
    if (weather.latitude == null || weather.longitude == null) continue;

    const latDiff = weather.latitude - station.lat;
    const lonDiff = weather.longitude - station.lon;
    const distance = Math.sqrt(latDiff * latDiff + lonDiff * lonDiff);

    if (distance < bestDistance) {
      bestDistance = distance;
      bestMatch = weather;
    }
  }

  const current = bestMatch?.current || {};

  return {
    json: {
      station_name: station.station_name,
      lon: station.lon,
      lat: station.lat,
      // Current AQI & Pollutants
      last_aqi: station.aqi_overall,
      last_pm25: station.pm25,
      last_pm10: station.pm10,
      dominant_pollutant: station.dominant_pollutant,

      // Weather from Open-Meteo
      wind_speed_kmh: current.wind_speed_10m != null ? Math.round(current.wind_speed_10m * 10) / 10 : null,
      wind_degrees: current.wind_direction_10m != null ? current.wind_direction_10m : null,

      // AQICN station weather data
      station_wind_speed_ms: station.station_wind_speed_ms,
      wind_gust_ms: station.wind_gust_ms,
      humidity: station.humidity,
      temperature: station.temperature,
      pressure: station.pressure,
      dew_point: station.dew_point,

      // Additional pollutants
      o3: station.o3,
      no2: station.no2,
      so2: station.so2,
      co: station.co,

      // Forecast fields
      forecast_pm25_tomorrow: station.forecast_pm25_tomorrow,
      forecast_pm25_day2: station.forecast_pm25_day2,
      forecast_pm10_tomorrow: station.forecast_pm10_tomorrow,
      forecast_pm10_day2: station.forecast_pm10_day2,
      forecast_uvi_tomorrow: station.forecast_uvi_tomorrow,
      forecast_uvi_day2: station.forecast_uvi_day2,

      // Timestamp
      last_updated: station.last_updated,

      _debug: {
        matched_lat: bestMatch?.latitude,
        matched_lon: bestMatch?.longitude,
        distance_deg: Math.round(bestDistance * 1000) / 1000,
        weather_count: weatherArray.length,
        has_pm25: station.pm25 != null,
        has_pm10: station.pm10 != null,
        has_forecast: station.forecast_pm25_tomorrow != null
      }
    }
  };
});

return merged;

const items = $input.all();

// Build values for bulk insert
const values = items.map(item => {
  const data = item.json;
  const stationName = data.station_name.replace(/'/g, "''");
  const lon = data.lon || 0;
  const lat = data.lat || 0;

  // Current AQI & Pollutants
  const aqi = data.last_aqi != null ? data.last_aqi : 'NULL';
  const pm25 = data.last_pm25 != null ? data.last_pm25 : 'NULL';
  const pm10 = data.last_pm10 != null ? data.last_pm10 : 'NULL';
  const dominantPollutant = data.dominant_pollutant != null ? `'${data.dominant_pollutant.replace(/'/g, "''")}'` : 'NULL';

  // Weather from Open-Meteo
  const windSpeed = data.wind_speed_kmh != null ? data.wind_speed_kmh : 'NULL';
  const windDeg = data.wind_degrees != null ? data.wind_degrees : 'NULL';

  // AQICN station weather
  const windSpeedMs = data.station_wind_speed_ms != null ? data.station_wind_speed_ms : 'NULL';
  const windGustMs = data.wind_gust_ms != null ? data.wind_gust_ms : 'NULL';
  const humidity = data.humidity != null ? data.humidity : 'NULL';
  const temperature = data.temperature != null ? data.temperature : 'NULL';
  const pressure = data.pressure != null ? data.pressure : 'NULL';
  const dewPoint = data.dew_point != null ? data.dew_point : 'NULL';

  // Additional pollutants
  const o3 = data.o3 != null ? data.o3 : 'NULL';
  const no2 = data.no2 != null ? data.no2 : 'NULL';
  const so2 = data.so2 != null ? data.so2 : 'NULL';
  const co = data.co != null ? data.co : 'NULL';

  // Forecast data
  const forecastPm25Tomorrow = data.forecast_pm25_tomorrow != null ? data.forecast_pm25_tomorrow : 'NULL';
  const forecastPm25Day2 = data.forecast_pm25_day2 != null ? data.forecast_pm25_day2 : 'NULL';
  const forecastPm10Tomorrow = data.forecast_pm10_tomorrow != null ? data.forecast_pm10_tomorrow : 'NULL';
  const forecastPm10Day2 = data.forecast_pm10_day2 != null ? data.forecast_pm10_day2 : 'NULL';
  const forecastUviTomorrow = data.forecast_uvi_tomorrow != null ? data.forecast_uvi_tomorrow : 'NULL';
  const forecastUviDay2 = data.forecast_uvi_day2 != null ? data.forecast_uvi_day2 : 'NULL';
  const lastUpdated = data.last_updated != null ? `'${data.last_updated}'` : 'NULL';

  return `('${stationName}', ST_MakePoint(${lon}, ${lat})::geography, ${aqi}, ${pm25}, ${pm10}, ${windSpeed}, ${windDeg}, now(), ${windSpeedMs}, ${windGustMs}, ${humidity}, ${temperature}, ${pressure}, ${dewPoint}, ${dominantPollutant}, ${o3}, ${no2}, ${so2}, ${co}, ${forecastPm25Tomorrow}, ${forecastPm25Day2}, ${forecastPm10Tomorrow}, ${forecastPm10Day2}, ${forecastUviTomorrow}, ${forecastUviDay2}, ${lastUpdated})`;
}).join(',');

const query = `
  insert into real_time_stations (
    station_name, 
    location, 
    last_aqi, 
    last_pm25, 
    last_pm10, 
    wind_speed_kmh, 
    wind_degrees, 
    updated_at,
    station_wind_speed_ms,
    wind_gust_ms,
    humidity,
    temperature,
    pressure,
    dew_point,
    dominant_pollutant,
    o3,
    no2,
    so2,
    co,
    forecast_pm25_tomorrow,
    forecast_pm25_day2,
    forecast_pm10_tomorrow,
    forecast_pm10_day2,
    forecast_uvi_tomorrow,
    forecast_uvi_day2,
    last_updated
  ) 
  values ${values}

`;

return [{
  json: {
    query: query,
    count: items.length
  }
}];

// Re-attach the lat/lon we already know (from the map/bounds call) instead
// of trusting the /feed/ response's own city.geo, since that's a different
// precision/order and isn't guaranteed to match what we filtered on.
const stations = $('Filter Malaysian Stations1').all().map(i => i.json);
const details = $input.all().map(i => i.json);

return stations.map((station, idx) => {
  const d = details[idx]?.data || {};
  const iaqi = d.iaqi || {};
  const forecast = d.forecast?.daily || {};

  // Extract forecast values
  const pm25Forecast = forecast.pm25 || [];
  const pm10Forecast = forecast.pm10 || [];
  const uviForecast = forecast.uvi || [];

  return {
    json: {
      station_name: station.station.name,
      lat: station.lat,
      lon: station.lon,

      // Current AQI
      aqi_overall: station.aqi ? parseInt(station.aqi) : null,

      // Current Pollutants
      pm25: iaqi.pm25?.v ?? null,
      pm10: iaqi.pm10?.v ?? null,
      dominant_pollutant: d.dominentpol || null,

      // Current Weather
      temperature: iaqi.t?.v ?? null,
      humidity: iaqi.h?.v ?? null,
      station_wind_speed_ms: iaqi.w?.v ?? null,
      wind_gust_ms: iaqi.wg?.v ?? null,
      pressure: iaqi.p?.v ?? null,
      dew_point: iaqi.dew?.v ?? null,

      // Additional Pollutants
      o3: iaqi.o3?.v ?? null,
      no2: iaqi.no2?.v ?? null,
      so2: iaqi.so2?.v ?? null,
      co: iaqi.co?.v ?? null,

      // Forecast Values
      forecast_pm25_tomorrow: pm25Forecast[1]?.avg ?? null,
      forecast_pm25_day2: pm25Forecast[2]?.avg ?? null,
      forecast_pm10_tomorrow: pm10Forecast[1]?.avg ?? null,
      forecast_pm10_day2: pm10Forecast[2]?.avg ?? null,
      forecast_uvi_tomorrow: uviForecast[1]?.avg ?? null,
      forecast_uvi_day2: uviForecast[2]?.avg ?? null,

      // Timestamp
      last_updated: d.time?.iso || null
    }
  };
});
